mapper.select:
SELECT
    o.id, o.org_name, o.org_type, o.parent_id, o.org_level,
    o.enterprise_id, o.company_id, o.leader_user_id, o.sort,
    o.status, o.create_time, o.update_time,
    u.username AS leader_username
FROM sys_org o
LEFT JOIN user u ON u.id = o.leader_user_id


        AND o.id = #{id}


        AND o.org_name LIKE CONCAT('%', #{orgName}, '%')


        AND o.org_type = #{orgType}


        AND o.parent_id = #{parentId}


        AND o.status = #{status}


        AND o.enterprise_id = #{enterpriseId}


ORDER BY o.org_level ASC, o.sort ASC, o.id ASC

