org_name = #{orgName}, org_type = #{orgType}, parent_id = #{parentId}, org_level = #{orgLevel}, enterprise_id = #{enterpriseId}, company_id = #{companyId}, leader_user_id = #{leaderUserId}, sort = #{sort}, status = #{status}, update_time = #{updateTime}
